    #[doc = " ::NV_ENC_ERR_DEVICE_NOT_EXIST \\n"]
    #[doc = " ::NV_ENC_ERR_UNSUPPORTED_PARAM \\n"]
    #[doc = " ::NV_ENC_ERR_OUT_OF_MEMORY \\n"]
